def decrypt_val(val: str) -> str:
    if not val:
        return val
    try:
        cipher = get_cipher()
        return cipher.decrypt(val.encode('utf-8')).decode('utf-8')
    except InvalidToken:
        # D1: distinguish two failure modes instead of silently returning the raw value:
        #  - the value LOOKS like a real Fernet token but won't decrypt (wrong key / corruption):
        #    fail LOUD — never hand ciphertext back as if it were a usable plaintext credential.
        #  - the value is legacy plaintext that was never encrypted: return it as-is (bounded
        #    backwards-compat), which is returning plaintext-as-plaintext, not ciphertext-as-plaintext.
        if _looks_like_fernet_token(val):
            logger.error("🔓 decrypt_val: value is an encrypted Fernet token but decryption FAILED "
                         "(wrong ENCRYPTION_KEY or corrupted ciphertext). Refusing to return ciphertext.")
            raise DecryptionError("Fernet token failed to decrypt")
        return val
    except Exception as e:
        # Unexpected error (not a decrypt-validity failure): log loudly, do not mask.
        logger.error(f"🔓 decrypt_val: unexpected error during decryption: {e}")
        raise DecryptionError(str(e))

async def execute_fix(fix_action: str, u_id=None):
    # D6: hard allow-list guard — never execute anything outside the approved set.
    if fix_action not in ALLOWED_FIX_ACTIONS:
        logger.warning(f"🩺 Health Agent: rejected non-allowlisted action '{fix_action}' — treating as wait.")
        return

    # D6: scope restart_ws/relogin to the originating user when the triggering error was
    # user-scoped; fall back to all users only for genuinely global errors (u_id is None).
    if u_id is not None and int(u_id) in USER_CONTEXTS:
        targets = [(int(u_id), USER_CONTEXTS[int(u_id)])]
    else:
        targets = list(USER_CONTEXTS.items())

    if fix_action == "restart_ws":
        logger.info(f"🩺 Health Agent executing: restart_ws (scope: {'user ' + str(u_id) if u_id is not None else 'all users'})")

# A2: when a `state` value is present it MUST be a valid, unexpired, single-use signed
# nonce (see generate_oauth_state). We no longer trust a raw `state=user_id` at face value.
state = request.query_params.get("state")
state_present = bool(state and state != "None")
if state_present:
    bound_uid = consume_oauth_state(state)
    if bound_uid is None:
        print("⚠️ /fyers/callback rejected: invalid/expired/replayed OAuth state", flush=True)
        return RedirectResponse(url="/login?reason=invalid_state")
    user_id = bound_uid

def generate_oauth_state(user_id) -> str:
    """Return a signed, single-use, short-TTL OAuth `state` nonce bound to the initiating user."""
    nonce = os.urandom(16).hex()
    return _get_oauth_serializer().dumps({"uid": int(user_id), "nonce": nonce})


def consume_oauth_state(state: Optional[str], now: Optional[float] = None) -> Optional[int]:
    """
    Validate an OAuth `state` value and return the bound integer user id, or None if invalid.

    Rejects when: state is missing, signature is bad/forged, the token is older than
    OAUTH_STATE_TTL_SECONDS, or the nonce has already been consumed (replay). On success the
    nonce is marked used so a second presentation of the same valid state fails.
    """
    ...
    try:
        data = _get_oauth_serializer().loads(state, max_age=OAUTH_STATE_TTL_SECONDS)
    except (BadSignature, SignatureExpired, ValueError, TypeError):
        return None
    ...
    if nonce in _USED_OAUTH_NONCES:
        return None  # replay of an already-consumed nonce
    _USED_OAUTH_NONCES[nonce] = now + OAUTH_STATE_TTL_SECONDS
